/**
 * 02-admin-setup.spec.ts
  *
   * SUITE: Admin Login + Company Setup
    *
     * Tests:
      *   1. Admin login via API — correct credentials return token
       *   2. Admin login via API — wrong password returns 401
        *   3. Admin login via UI — fills login form, verifies dashboard loads
         *   4. Fetch company profile — GET /api/company returns company data
          *   5. Update company profile — PUT /api/company saves changes
           *   6. Create a customer — POST /api/customers
            *   7. Create a shipper — POST /api/shippers
             *   8. Create a driver + set portal password — POST /api/drivers + PATCH
              *   9. Create a truck — POST /api/trucks
               *  10. List employees — GET /api/employees returns admin user
                */

                import { test, expect } from '@playwright/test';
                import { loadContext, saveContext, apiRequest } from './helpers';

                test.describe('Admin Login and Company Setup', () => {

                  test('01 - Admin login via API returns token', async ({ request }) => {
                      const ctx = loadContext();
                          const res = await request.post(ctx.baseUrl + '/api/auth/login', {
                                data: { email: ctx.adminEmail, password: ctx.adminPassword },
                                    });
                                        expect(res.ok()).toBeTruthy();
                                            const body = await res.json();
                                                expect(body.token).toBeTruthy();
                                                    expect(body.user.role).toBe('admin');
                                                        // Refresh the stored token in case global-setup token expired
                                                            saveContext({ adminToken: body.token });
                                                              });

                                                                test('02 - Admin login rejects wrong password', async ({ request }) => {
                                                                    const ctx = loadContext();
                                                                        const res = await request.post(ctx.baseUrl + '/api/auth/login', {
                                                                              data: { email: ctx.adminEmail, password: 'wrongpassword' },
                                                                                  });
                                                                                      expect(res.status()).toBe(401);
                                                                                          const body = await res.json();
                                                                                              expect(body.error).toMatch(/invalid credentials/i);
                                                                                                });

                                                                                                  test('03 - Admin login rejects unknown email', async ({ request }) => {
                                                                                                      const ctx = loadContext();
                                                                                                          const res = await request.post(ctx.baseUrl + '/api/auth/login', {
                                                                                                                data: { email: 'nobody@nowhere.test', password: 'whatever' },
                                                                                                                    });
                                                                                                                        expect(res.status()).toBe(401);
                                                                                                                          });
                                                                                                                          
                                                                                                                            test('04 - GET /api/company returns company profile', async ({ request }) => {
                                                                                                                                const ctx = loadContext();
                                                                                                                                    const res = await request.get(ctx.baseUrl + '/api/company', {
                                                                                                                                          headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                              });
                                                                                                                                                  expect(res.ok()).toBeTruthy();
                                                                                                                                                      const body = await res.json();
                                                                                                                                                          expect(body.name).toBe(ctx.companyName);
                                                                                                                                                              expect(body.id).toBe(ctx.companyId);
                                                                                                                                                                });
                                                                                                                                                                
                                                                                                                                                                  test('05 - PUT /api/company updates company profile', async ({ request }) => {
                                                                                                                                                                      const ctx = loadContext();
                                                                                                                                                                          const res = await request.put(ctx.baseUrl + '/api/company', {
                                                                                                                                                                                headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                      data: {
                                                                                                                                                                                              name: ctx.companyName,
                                                                                                                                                                                                      email: ctx.adminEmail,
                                                                                                                                                                                                              phone: '615-555-0199',
                                                                                                                                                                                                                      address: '1400 Truck Stop Blvd',
                                                                                                                                                                                                                              city: 'Nashville',
                                                                                                                                                                                                                                      state: 'TN',
                                                                                                                                                                                                                                              zip: '37201',
                                                                                                                                                                                                                                                      invoice_prefix: 'TRL',
                                                                                                                                                                                                                                                              payment_terms: 30,
                                                                                                                                                                                                                                                                    },
                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                            expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                const body = await res.json();
                                                                                                                                                                                                                                                                                    expect(body.city).toBe('Nashville');
                                                                                                                                                                                                                                                                                        expect(body.invoice_prefix).toBe('TRL');
                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                            test('06 - POST /api/customers creates a customer', async ({ request }) => {
                                                                                                                                                                                                                                                                                                const ctx = loadContext();
                                                                                                                                                                                                                                                                                                    const res = await request.post(ctx.baseUrl + '/api/customers', {
                                                                                                                                                                                                                                                                                                          headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                data: {
                                                                                                                                                                                                                                                                                                                        name: 'Midwest Steel Corp',
                                                                                                                                                                                                                                                                                                                                email: 'billing@midweststeel.test',
                                                                                                                                                                                                                                                                                                                                        phone: '312-555-7700',
                                                                                                                                                                                                                                                                                                                                                billing_address: '555 Industrial Way',
                                                                                                                                                                                                                                                                                                                                                        city: 'Chicago',
                                                                                                                                                                                                                                                                                                                                                                state: 'IL',
                                                                                                                                                                                                                                                                                                                                                                        zip: '60601',
                                                                                                                                                                                                                                                                                                                                                                                payment_terms: 30,
                                                                                                                                                                                                                                                                                                                                                                                      },
                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                              expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                  const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                      expect(body.id).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                          expect(body.company_name || body.name).toBe('Midwest Steel Corp');
                                                                                                                                                                                                                                                                                                                                                                                                              saveContext({ customerId: body.id });
                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                  test('07 - POST /api/shippers creates a shipper', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                      const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                          const res = await request.post(ctx.baseUrl + '/api/shippers', {
                                                                                                                                                                                                                                                                                                                                                                                                                                headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                      data: {
                                                                                                                                                                                                                                                                                                                                                                                                                                              name: 'Great Lakes Distribution',
                                                                                                                                                                                                                                                                                                                                                                                                                                                      address: '200 Warehouse Row',
                                                                                                                                                                                                                                                                                                                                                                                                                                                              city: 'Detroit',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      state: 'MI',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              zip: '48201',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      contact_name: 'Jim Dock',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              phone: '313-555-4400',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      email: 'dock@greatlakes.test',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            expect(body.id).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                saveContext({ shipperId: body.id });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    test('08 - POST /api/drivers creates a driver with portal access', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Create the driver
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const createRes = await request.post(ctx.baseUrl + '/api/drivers', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            data: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    name: 'Bobby Roadhog',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            phone: ctx.driverPhone,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    email: 'bobby@thunderridge.test',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            license_number: 'CDL-TN-' + ctx.driverPhone,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    license_expiry: '2027-06-01',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            medical_card_expiry: '2026-12-01',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    hire_date: '2024-01-15',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            status: 'available',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          expect(createRes.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const driver = await createRes.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  expect(driver.id).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      saveContext({ driverId: driver.id });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Set the driver portal password
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const patchRes = await request.patch(ctx.baseUrl + '/api/drivers/' + driver.id, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          data: { portal_password: ctx.driverPassword },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  expect(patchRes.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      test('09 - POST /api/trucks creates a truck', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const res = await request.post(ctx.baseUrl + '/api/trucks', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          data: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  unit_number: 'T-101',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          type: 'tractor',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  make: 'Kenworth',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          model: 'T680',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  year: 2022,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          vin: '1XKWDB0X8NJ' + ctx.driverPhone,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  license_plate: 'TN-HAULX',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          state: 'TN',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  status: 'active',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        expect(body.id).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            expect(body.unit_number).toBe('T-101');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                test('10 - GET /api/employees returns admin user', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const res = await request.get(ctx.baseUrl + '/api/employees', {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              headers: { Authorization: 'Bearer ' + ctx.adminToken },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      expect(res.ok()).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const body = await res.json();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              expect(Array.isArray(body)).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const admin = body.find((u) => u.email === ctx.adminEmail);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      expect(admin).toBeTruthy();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          expect(admin.role).toBe('admin');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              test('11 - Unauthorized request is rejected', async ({ request }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const res = await request.get(ctx.baseUrl + '/api/loads');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          expect(res.status()).toBe(401);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              test('12 - UI: Admin dashboard loads after login', async ({ page }) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const ctx = loadContext();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await page.goto(ctx.uiUrl + '/');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await page.waitForLoadState('networkidle');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Set token directly so we skip UI login form
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  await page.evaluate((args) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        localStorage.setItem('hf_token', args.token);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              localStorage.setItem('hf_user', JSON.stringify({ email: args.email, role: 'admin', company_id: args.companyId }));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }, { token: ctx.adminToken, email: ctx.adminEmail, companyId: ctx.companyId });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await page.reload();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          await page.waitForLoadState('networkidle');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Dashboard should show navigation tabs
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const nav = page.locator('nav, aside, [class*="sidebar"], [class*="nav"]').first();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await expect(nav).toBeVisible({ timeout: 10000 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
